body:
EmitOMIR assumes any NLA used with a tracker has an absolute path.  This is an issue when dedup adds an NLA to a tracker and it isn't the full path: this produces OMIR with only a partial path to the top module.  The issue looks like it is in this code: https://github.com/llvm/circt/blob/cf46c8ad17ad496b0d64ba7d134a61da281419c3/lib/Dialect/FIRRTL/Transforms/EmitOMIR.cpp#L284-L290

```mlir
#loc = loc(unknown)
firrtl.circuit "Top" attributes {annotations = [{
  class = "freechips.rocketchip.objectmodel.OMIRAnnotation",
  nodes = [
    {
      info = #loc,
      id = "OMID:0",
      fields = {
        omType = {info = #loc, index = 0, value = ["OMString:OMLazyModule", "OMString:OMSRAM"]},
        instancePath = {info = #loc, index = 1, value = {omir.tracker, id = 0, type = "OMMemberReferenceTarget"}}
      }
    }
  ]
}]} {
  firrtl.nla @nla [#hw.innerNameRef<@SRAMPaths::@sub>, @Submodule]
  firrtl.extmodule @MySRAM()
  firrtl.module @Submodule() {
    firrtl.instance mem1 {annotations = [{circt.nonlocal = @nla, class = "freechips.rocketchip.objectmodel.OMIRTracker", id = 0}]} @MySRAM()
    //firrtl.instance mem1 {annotations = [{class = "freechips.rocketchip.objectmodel.OMIRTracker", id = 0}]} @MySRAM()
  }
  firrtl.module @SRAMPaths() {
    firrtl.instance sub sym @sub {annotations = [{circt.nonlocal = @nla, class = "circt.nonlocal"}]} @Submodule()
  }
  firrtl.module @Top() {
    firrtl.instance paths @SRAMPaths()
  }
}
```

This example produces
```mlir
sv.verbatim "[\0A  {\0A    \22info\22: \22UnlocatableSourceInfo\22,\0A    \22id\22: \22OMID:0\22,\0A    \22fields\22: [\0A      {\0A        \22info\22: \22UnlocatableSourceInfo\22,\0A        \22name\22: \22omType\22,\0A        \22value\22: [\0A          \22OMString:OMLazyModule\22,\0A          \22OMString:OMSRAM\22\0A        ]\0A      },\0A      {\0A        \22info\22: \22UnlocatableSourceInfo\22,\0A        \22name\22: \22instancePath\22,\0A        \22value\22: \22OMMemberInstanceTarget:~Top|{{0}}/{{1}}:{{2}}/{{3}}:{{4}}\22\0A      }\0A    ]\0A  }\0A]" {output_file = #hw.output_file<"omir.json", excludeFromFileList>, symbols = [@SRAMPaths, #hw.innerNameRef<@SRAMPaths::@sub>, @Submodule, #hw.innerNameRef<@Submodule::@mem1>, @MySRAM]}
```
where the path is
```
~Top|{{0}}/{{1}}:{{2}}/{{3}}:{{4}}
[@SRAMPaths, #hw.innerNameRef<@SRAMPaths::@sub>, @Submodule, #hw.innerNameRef<@Submodule::@mem1>, @MySRAM]
=>
~Top|SRAMPaths/sub:Submodule/mem1:MySRAM
```

The correct output would be:
```mlir
  sv.verbatim "[\0A  {\0A    \22info\22: \22UnlocatableSourceInfo\22,\0A    \22id\22: \22OMID:0\22,\0A    \22fields\22: [\0A      {\0A        \22info\22: \22UnlocatableSourceInfo\22,\0A        \22name\22: \22omType\22,\0A        \22value\22: [\0A          \22OMString:OMLazyModule\22,\0A          \22OMString:OMSRAM\22\0A        ]\0A      },\0A      {\0A        \22info\22: \22UnlocatableSourceInfo\22,\0A        \22name\22: \22instancePath\22,\0A        \22value\22: \22OMMemberInstanceTarget:~Top|{{0}}/{{1}}:{{2}}/{{3}}:{{4}}/{{5}}:{{6}}\22\0A      }\0A    ]\0A  }\0A]" {output_file = #hw.output_file<"omir.json", excludeFromFileList>, symbols = [@Top, #hw.innerNameRef<@Top::@paths>, @SRAMPaths, #hw.innerNameRef<@SRAMPaths::@sub>, @Submodule, #hw.innerNameRef<@Submodule::@mem1>, @MySRAM]}
```
Where the path is: 
```
~Top|{{0}}/{{1}}:{{2}}/{{3}}:{{4}}/{{5}}:{{6}}
[@Top, #hw.innerNameRef<@Top::@paths>, @SRAMPaths, #hw.innerNameRef<@SRAMPaths::@sub>, @Submodule, #hw.innerNameRef<@Submodule::@mem1>, @MySRAM]
=>
~Top|Top/paths:SRAMPaths/sub:Submodule/mem1:MySRAM
```
